import React, { forwardRef, useContext } from 'react'
import { format } from 'date-fns'
import Highlighter from 'react-highlight-words'
import uniqid from 'uniqid'

import GitHubIcon from '@mui/icons-material/GitHub'
import LanguageIcon from '@mui/icons-material/Language'
import LaunchIcon from '@mui/icons-material/Launch'
import LinkIcon from '@mui/icons-material/Link'
import LinkedInIcon from '@mui/icons-material/LinkedIn'
import MailIcon from '@mui/icons-material/Mail'
import LocalPhoneIcon from '@mui/icons-material/PhoneAndroid'
import LocationOnIcon from '@mui/icons-material/ShareLocation'
import Avatar from '@mui/material/Avatar'

import { qrCode } from '../../assets'
import { LanguageContext } from '../../contexts/language'
import {
  CertificateType,
  type ICertificate,
  type IEducation,
  type IExperience,
  type IExperienceProject,
  type IProjects
} from '../../utils/Portfolio'

import './CvOneSideV2.css'

interface Props {
  // children?: ReactNode;
  // type: "submit" | "button";
}

export type Ref = HTMLDivElement

const CvOneSideV2 = forwardRef<Ref, Props>((props, ref) => {
  const { dictionary, portfolio } = useContext(LanguageContext)
  const {
    about,
    contact,
    experience,
    education,
    backend,
    frontend,
    languages,
    programmingLanguages,
    certificates,
    projects,
    database,
    devOps
  } = portfolio

  const getPageMargins = (): string => {
    return `@page { size: Legal; margin: 20px 5px 10px 5px !important; }`
  }

  return (
    <div className="cv_one_side light" ref={ref}>
      <style>{getPageMargins()}</style>
      <section className="row justify-content-around">
        <div className="col-4">
          <h2 className="complete-name">{about.completeName}</h2>
          <h5 className="role">{about.role}</h5>
        </div>
        <div className="col-7 row justify-content-end d-0">
          <section className="contact-info col-12 p-0">
            <a
              href={contact.website}
              target="_blank"
              rel="noreferrer"
              aria-label="github"
            >
              <LanguageIcon fontSize="inherit" />{' '}
              {contact.website.replace('https://', '')}
            </a>
          </section>
          <section className="contact-info col-12 p-0">
            <a
              href={contact.linkedin}
              target="_blank"
              rel="noreferrer"
              aria-label="linkedin"
            >
              <LinkedInIcon fontSize="inherit" />{' '}
              {contact.linkedin.replace('https://www.linkedin.com/', '')}
            </a>
          </section>
          <section className="contact-info col-auto p-0">
            <LocationOnIcon fontSize="inherit" /> {contact.location}
          </section>
          <section className="contact-info col-auto">
            <a href={`mailto:${contact.email}`}>
              <MailIcon fontSize="inherit" /> {contact.email}
            </a>
          </section>
          <section className="contact-info col-auto p-0">
            <LocalPhoneIcon fontSize="inherit" /> {contact.phone}
          </section>
        </div>
        <div className="col-1 section_qr_code">
          <Avatar
            variant="square"
            src={qrCode}
            alt={contact.website}
            style={{ padding: 0, display: 'contents' }}
            imgProps={{ style: { objectFit: 'contain' } }}
          ></Avatar>
        </div>
      </section>
      <section className="section">
        <h3 className="section_title">{dictionary.summary}</h3>
        <Highlighter
          highlightClassName="highlighted-text"
          className="about-me"
          autoEscape={true}
          searchWords={about.aboutMeHighlights}
          textToHighlight={about.aboutMe}
        />
      </section>
      <section className="section">
        <h3 className="section_title">{dictionary.education}</h3>
        <div className="d-flex flex-column">
          {education.map((item) => (
            <EducationItem key={uniqid()} item={item} />
          ))}
        </div>
      </section>
      <section className="section">
        <h3 className="section_title">{dictionary.experience}</h3>
        {experience.map((item) => (
          <ExperienceItem key={uniqid()} {...item} />
        ))}
      </section>
      <section className="section page_break html2pdf__page-break">
        <h3 className="section_title">{dictionary.technicalSkills}</h3>
        <ul className="section_item_description_list">
          <li className="section_item_description_list_item">
            <span style={{ fontWeight: 'bold' }}>
              {dictionary.programmingLanguages}:
            </span>{' '}
            {programmingLanguages.join(', ')}
          </li>
          <li className="section_item_description_list_item">
            <span style={{ fontWeight: 'bold' }}>{dictionary.backEnd}:</span>{' '}
            {backend.join(', ')}
          </li>
          <li className="section_item_description_list_item">
            <span style={{ fontWeight: 'bold' }}>{dictionary.frontEnd}:</span>{' '}
            {frontend.join(', ')}
          </li>
          <li className="section_item_description_list_item">
            <span style={{ fontWeight: 'bold' }}>{dictionary.database}:</span>{' '}
            {database.join(', ')}
          </li>
          <li className="section_item_description_list_item">
            <span style={{ fontWeight: 'bold' }}>{dictionary.devOps}:</span>{' '}
            {devOps.join(', ')}
          </li>
          <li className="section_item_description_list_item">
            <span style={{ fontWeight: 'bold' }}>{dictionary.languages}:</span>{' '}
            {languages
              .map((language) => `${language.name} (${language.level})`)
              .join(', ')}
          </li>
        </ul>
      </section>
      <section className="section">
        <h3 className="section_title">{dictionary.certifications}</h3>
        <div className="d-flex flex-row flex-wrap">
          {certificates
            .filter((c) =>
              [
                CertificateType.CERTIFICATION,
                CertificateType.SPECIALIZATION,
                CertificateType.TEST
              ].includes(c.type)
            )
            .map((item, idx) => (
              <CertificateItem
                key={uniqid()}
                item={item}
                idx={idx}
                showTags={false}
              />
            ))}
        </div>
      </section>
      <section className="section  page_break">
        <h3 className="section_title">{dictionary.projects}</h3>
        <div className="d-flex flex-row flex-wrap">
          {projects.map((item, idx) => (
            <ProjectItem key={uniqid()} item={item} idx={idx} />
          ))}
        </div>
      </section>
      <section className="section">
        <h3 className="section_title">{dictionary.certificates}</h3>
        <div className="d-flex flex-row flex-wrap">
          {certificates
            .filter(
              (c) =>
                ![
                  CertificateType.CERTIFICATION,
                  CertificateType.SPECIALIZATION,
                  CertificateType.TEST
                ].includes(c.type)
            )
            .filter((c) => {
              // * Exclude certificates outdated more than 4 years ago
              const currentYear = new Date().getFullYear()
              const certificateYear = new Date(c.date).getFullYear()
              return currentYear - certificateYear <= 4
            })
            .map((item, idx) => (
              <CertificateItem key={uniqid()} item={item} idx={idx} />
            ))}
        </div>
      </section>
    </div>
  )
})

const ProjectItem: React.FC<{ item: IProjects; idx: number }> = ({
  item,
  idx
}): JSX.Element => {
  return (
    <section
      className={`certificate_item col-6 ${
        idx % 2 === 0 ? 'pe-3' : 'pe-1'
      } mb-1 pb-1`}
    >
      <div className="d-flex">
        <p className="section_item_title flex-grow-1">{item.name}</p>
        <p
          className="section_item_date text_end"
          style={{ whiteSpace: 'nowrap' }}
        >
          {item.livePreview && (
            <a
              href={item.livePreview}
              target="_blank"
              rel="noreferrer"
              aria-label="live preview"
              className="link link--icon-cv"
            >
              <LaunchIcon fontSize="small" />
            </a>
          )}
        </p>
      </div>
      <div className="d-flex">
        <p className="section_item_subtitle flex-grow-1 mb-1">
          {item.description}
        </p>
        {item.sourceCode && (
          <a
            href={item.sourceCode}
            target="_blank"
            rel="noreferrer"
            aria-label="live repository"
            className="link link--icon-cv"
          >
            <GitHubIcon fontSize="small" />
          </a>
        )}
      </div>
      {/* <p className="section_item_subtitle flex-grow-1">{item.stack}</p> */}
      {item.stack != null && (
        <ul className="d-flex flex-wrap">
          {item.stack.map((stack) => (
            <li
              key={uniqid()}
              className="color-text-muted me-2 mb-1 li_small"
              style={{ fontWeight: 500 }}
            >
              {stack}
            </li>
          ))}
        </ul>
      )}
    </section>
  )
}
const CertificateItem: React.FC<{
  item: ICertificate
  idx: number
  showTags?: boolean
}> = ({ item, idx, showTags = true }): JSX.Element => {
  const { portfolio } = useContext(LanguageContext)
  const { locale } = portfolio
  return (
    <section
      className={`certificate_item col-6 ${
        idx % 2 === 0 ? 'pe-3' : 'pe-1'
      } mb-1 pb-1 page_break_inside`}
    >
      <div className="d-flex">
        <p className="section_item_title flex-grow-1">{item.name}</p>
        <p
          className="section_item_date text_end"
          style={{ whiteSpace: 'nowrap' }}
        >
          {format(item.date + 'T05:00:00Z', 'dd MMM yyyy', {
            locale
          })}
        </p>
      </div>
      <div className="d-flex">
        <p className="section_item_subtitle flex-grow-1">{item.organization}</p>
        {item.credentialUrl && (
          <a
            href={item.credentialUrl}
            target="_blank"
            rel="noreferrer"
            aria-label="live preview"
            className="link link--icon-cv no_padding"
          >
            <LinkIcon fontSize={'small'} />
          </a>
        )}
      </div>
      {/* <div className="d-flex">
        <p className="section_item_subtitle flex-grow-1">
          {item.description}
        </p>
      </div> */}
      {showTags && item.tags != null && (
        <ul className="d-flex flex-wrap">
          {item.tags.map((stack) => (
            <li
              key={uniqid()}
              className="color-text-muted me-2 mb-1 li_small"
              style={{ fontWeight: 500 }}
            >
              {stack}
            </li>
          ))}
        </ul>
      )}
    </section>
  )
}

const ExperienceItem = (item: IExperience): JSX.Element => {
  return (
    <section className="section_item experience_item">
      <div className="d-flex">
        <p className="section_item_title flex-grow-1">
          {item.title} |{' '}
          <span className="section_item_experience_institution">
            {item.institution}
          </span>
        </p>
        <p className="section_item_date">{item.dateShort}</p>
      </div>
      <div className="d-flex flex-row-reverse">
        {item.showLocation !== false ? (
          <p className="section_item_location">{item.location}</p>
        ) : null}
      </div>
      {item.description != null ? (
        <ul className="section_item_description_list">
          {item.description.map((description) => (
            <li key={uniqid()} className="section_item_description_item">
              <Highlighter
                highlightClassName="highlighted-text"
                autoEscape={true}
                searchWords={item.descriptionHighlights ?? []}
                textToHighlight={description}
              />
            </li>
          ))}
        </ul>
      ) : null}
      {item.projects != null
        ? item.projects.map((project) => (
            <ExperienceProjectItem key={uniqid()} {...project} />
          ))
        : null}
      {item.technologies != null && (
        <ul className="d-flex flex-wrap mt-1">
          {item.technologies.map((technology) => (
            <li
              key={uniqid()}
              className="section_item_subtitle_technology_item"
            >
              {technology}
            </li>
          ))}
        </ul>
      )}
    </section>
  )
}

const ExperienceProjectItem = (item: IExperienceProject): JSX.Element => {
  const { dictionary } = useContext(LanguageContext)
  return (
    <section>
      <div className="d-flex mt-2">
        <p className="section_item_subtitle flex-grow-1 text-justify">
          <span className="section_item_subtitle_project">
            {dictionary.project}:
          </span>{' '}
          <span>
            <b>{item.institution}</b> - {item.name}
          </span>
        </p>
      </div>
      <div className="d-flex mt-1">
        <p className="subsection_item_date flex-grow-1">{item.date}</p>
        <p className="subsection_item_location">{item.location}</p>
      </div>
      {item.description != null ? (
        <ul className="section_item_description_list">
          {item.description.map((description) => (
            <li key={uniqid()} className="section_item_description_item">
              <Highlighter
                highlightClassName="highlighted-text"
                autoEscape={true}
                searchWords={item.descriptionHighlights ?? []}
                textToHighlight={description}
              />
            </li>
          ))}
        </ul>
      ) : null}
      {item.technologies != null ? (
        <div className="d-flex mt-1">
          <p className="section_item_subtitle flex-grow-1 text-justify">
            <span style={{ fontWeight: 'bold' }}>
              {dictionary.technologiesUsed}:
            </span>{' '}
            {item.technologies.join(', ')}
          </p>
        </div>
      ) : null}
    </section>
  )
}

const EducationItem: React.FC<{
  item: IEducation
}> = ({ item }): JSX.Element => {
  return (
    <section className="section_item">
      <div className="d-flex">
        <p className="section_item_title col-6">{item.title}</p>
        <p className="section_item_subtitle flex-grow-1">{item.institution}</p>
        <p className="section_item_date col-auto">{item.date}</p>
      </div>
    </section>
  )
}

CvOneSideV2.displayName = 'CvOneSide'
export default CvOneSideV2
