import React from 'react'
import Highlighter from 'react-highlight-words'
import uniqid from 'uniqid'

import Avatar from '@mui/material/Avatar'

import {
  type IExperience,
  type TechStack,
  techStackIcon
} from '../../../utils/Portfolio'
import ExperienceProjectItem from '../ExperienceProjectItem/ExperienceProjectItem'

import './ExperienceItem.css'

const ExperienceItem: React.FC<IExperience> = (work) => {
  return (
    <li className="work">
      <div className="work-mask">
        {work?.logo ? (
          <Avatar
            variant="rounded"
            src={work.logo}
            alt={work.institution}
            className="work__logo"
            imgProps={{ style: { objectFit: 'contain', borderRadius: '20%' } }}
            sx={{ width: '4rem', height: '4rem' }}
          ></Avatar>
        ) : null}
        <h3 className="work__institution">{work.institution}</h3>
        <p className="work__title">{work.title}</p>
        <p className="work__date">{work.date}</p>
        {work.description != null ? (
          <ul className="work_description__grid">
            {work.description.map((detail) => (
              <li key={uniqid()} className="work__description__detail">
                <Highlighter
                  highlightClassName="highlighted-text"
                  autoEscape={true}
                  searchWords={(work.descriptionHighlights as string[]) ?? []}
                  textToHighlight={detail}
                />
              </li>
            ))}
          </ul>
        ) : null}
        {work.projects != null ? (
          <ul className="experience_projects__grid">
            {work.projects.map((project) => (
              <ExperienceProjectItem key={uniqid()} {...project} />
            ))}
          </ul>
        ) : null}
        {work.technologies != null ? (
          <ul className="work__technologies">
            {work.technologies.map((item) => (
              <li key={uniqid()} className="work__technologies-item">
                <i className={techStackIcon(item as TechStack)}></i> {item}
              </li>
            ))}
          </ul>
        ) : null}
      </div>
    </li>
  )
}

export default ExperienceItem
