import React, { useContext } from 'react'
import Highlighter from 'react-highlight-words'
import uniqid from 'uniqid'

import { LanguageContext } from '../../../contexts/language'
import { type IExperienceProject } from '../../../utils/Portfolio'

import './ExperienceProjectItem.css'

const ExperienceProjectItem: React.FC<IExperienceProject> = (project) => {
  const { dictionary } = useContext(LanguageContext)
  return (
    <li className="work_project">
      <p className="work_project__name text-justify">
        <span style={{ fontWeight: 'bold' }}>{dictionary.project}:</span>{' '}
        {project.institution} - {project.name}
      </p>
      {project.description != null ? (
        <ul className="work_project_description__grid">
          {project.description.map((detail) => (
            <li key={uniqid()} className="work_project__description_detail">
              <Highlighter
                highlightClassName="highlighted-text"
                autoEscape={true}
                searchWords={(project.descriptionHighlights as string[]) ?? []}
                textToHighlight={detail}
              />
            </li>
          ))}
        </ul>
      ) : null}
      {project.technologies != null ? (
        <ul className="work_project__technologies">
          {project.technologies.map((item) => (
            <li key={uniqid()} className="work_project__technologies-item">
              {item}
            </li>
          ))}
        </ul>
      ) : null}
    </li>
  )
}

export default ExperienceProjectItem
